string[] names = { "烘干箱A", "烘干箱B", "冷却塔", "传送带", "包装机" };
int total = 0, valid = 0, errors = 0;
Serial.Open();
for (int i = 0; i < 5; i++)
{
    var data = Serial.ReadLine();
    if (data == null) continue;
    total++;
    var parts = data.Split(',');
    var tempPart = parts[1].Split('=')[1];
    double temp = double.Parse(tempPart);
    if (temp > 150) { errors++; Print($"{names[i]} 异常"); }
    else { valid++; Print($"{names[i]}: {temp}°C"); }
}
Serial.Close();
Print($"总采集{total}条, 有效{valid}条, 异常{errors}条");
Print("===== 巡检报表完成 =====");
